SELECT ?player ?playerLabel 
WHERE {
  wd:Q3625678 p:P1346 ?statement.
  ?statement ps:P1346 ?player.
  ?statement pq:P585 ?date.
  OPTIONAL { ?player rdfs:label ?playerLabel. FILTER(LANG(?playerLabel) = 'en') }
}
ORDER BY DESC(?date)
LIMIT 1

